// -------------------------
// Imports
import Api from "../utils/Api.js";
import "../vendor/normalize.css";
import "./index.css";

// Images
import logoImg from "../images/spots-images/Logo.svg";
import closeIcon from "../images/spots-images/closeIcon.svg";
import faviconImg from "../images/favicon.ico";
import addIcon from "../images/spots-images/addIcon.svg";
import editIcon from "../images/spots-images/editIcon.svg";

// Validation + Modals
import {
  openModal,
  closeModal,
  setupModal,
  resetValidation,
  enableValidation,
} from "../scripts/validation.js";

// -------------------------
// API
const api = new Api({
  baseUrl: "https://around-api.en.tripleten-services.com/v1",
  headers: {
    authorization: "38511096-5799-43df-81af-9b90eb6a2ccb",
    "Content-Type": "application/json",
  },
});

// -------------------------
// DOM Elements
const profileAvatar = document.querySelector(".profile__avatar");
const profileNameEl = document.querySelector(".profile__name");
const profileDescriptionEl = document.querySelector(".profile__description");

const editProfileBtn = document.querySelector(".profile__edit-btn");
const addCardBtn = document.querySelector("#profile-add-btn");

const editProfileForm = document.querySelector("#profile-form");
const addCardForm = document.querySelector("#add_card_form");
const avatarForm = document.querySelector("#avatar-form");

const editProfileNameInput = document.querySelector("#profile-name-input");
const editProfileDescriptionInput = document.querySelector(
  "#profile-description-input",
);

const captionInput = document.querySelector("#profile-caption-input");
const imageInput = document.querySelector("#profile-image-input");
const avatarInput = document.querySelector("#avatar-input");

const cardsList = document.querySelector(".cards__list");

const cardTemplate = document
  .querySelector("#card-template")
  .content.querySelector(".card");

const previewImage = document.querySelector(".modal__image");
const previewCaption = document.querySelector(".modal__caption");

// -------------------------
// State
let currentUserId = null;
let cardToDelete = null;

// -------------------------
// Set Images
document.querySelector(".header__logo").src = logoImg;
document
  .querySelectorAll(".modal__close-btn img")
  .forEach((img) => (img.src = closeIcon));
document.querySelector(".profile__edit-btn img").src = editIcon;
document.querySelector("#profile-add-btn img").src = addIcon;

// Favicon
const link = document.createElement("link");
link.rel = "icon";
link.href = faviconImg;
document.head.appendChild(link);

// -------------------------
// Modals
const editProfileModal = setupModal(
  "#edit-profile-modal",
  [editProfileBtn],
  [".modal__close-btn"],
);

const newPostModal = setupModal(
  "#new-post-modal",
  [addCardBtn],
  [".modal__close-btn"],
);

const previewModal = setupModal("#preview-modal", [], [".modal__close-btn"]);

const editAvatarModal = setupModal(
  "#edit-avatar-modal",
  [profileAvatar],
  [".modal__close-btn"],
);

const confirmDeleteModal = setupModal(
  "#confirm-delete-modal",
  [],
  [".modal__close-btn", ".modal__cancel-btn"],
);

const confirmDeleteBtn = document.querySelector(".modal__confirm-btn");

// -------------------------
// User Info
function setUserInfo({ name, about, avatar, _id }) {
  profileNameEl.textContent = name;
  profileDescriptionEl.textContent = about;
  profileAvatar.src = avatar;
  currentUserId = _id;
}

// -------------------------
// Create Card
function createCard(data) {
  const card = cardTemplate.cloneNode(true);

  const title = card.querySelector(".card__title");
  const image = card.querySelector(".card__image");
  const likeBtn = card.querySelector(".card__like-button");
  const deleteBtn = card.querySelector(".card__delete-btn");

  title.textContent = data.name;
  image.src = data.link;
  image.alt = data.name;

  card.dataset.id = data._id;

  // Show like state
  if (data.likes.some((user) => user._id === currentUserId)) {
    likeBtn.classList.add("card__like-button_active");
  }

  // Like
  likeBtn.addEventListener("click", () => {
    const isLiked = likeBtn.classList.contains("card__like-button_active");

    const request = isLiked ? api.unlikeCard(data._id) : api.likeCard(data._id);

    request
      .then(() => {
        likeBtn.classList.toggle("card__like-button_active");
      })
      .catch(console.error);
  });

  // Delete (only own cards)
  if (data.owner._id !== currentUserId) {
    deleteBtn.remove();
  } else {
    deleteBtn.addEventListener("click", () => {
      cardToDelete = card;
      openModal(confirmDeleteModal);
    });
  }

  // Preview
  image.addEventListener("click", () => {
    previewImage.src = data.link;
    previewImage.alt = data.name;
    previewCaption.textContent = data.name;
    openModal(previewModal);
  });

  return card;
}

// -------------------------
// Delete Confirm
confirmDeleteBtn.addEventListener("click", () => {
  if (!cardToDelete) return;

  const id = cardToDelete.dataset.id;

  api
    .deleteCard(id)
    .then(() => {
      cardToDelete.remove();
      cardToDelete = null;
      closeModal(confirmDeleteModal);
    })
    .catch(console.error);
});

// -------------------------
// Edit Profile
editProfileForm.addEventListener("submit", (evt) => {
  evt.preventDefault();

  const btn = editProfileForm.querySelector(".modal__save-btn");
  btn.textContent = "Saving...";
  btn.disabled = true;

  api
    .editUserInfo({
      name: editProfileNameInput.value,
      about: editProfileDescriptionInput.value,
    })
    .then((data) => {
      setUserInfo(data);
      closeModal(editProfileModal);
    })
    .catch(console.error)
    .finally(() => {
      btn.textContent = "Save";
      btn.disabled = false;
    });
});

// -------------------------
// Add Card
addCardForm.addEventListener("submit", (evt) => {
  evt.preventDefault();

  const btn = addCardForm.querySelector(".modal__save-btn");
  btn.textContent = "Adding...";
  btn.disabled = true;

  api
    .addCard({
      name: captionInput.value,
      link: imageInput.value,
    })
    .then((cardData) => {
      const card = createCard(cardData);
      cardsList.prepend(card);
      addCardForm.reset();
      closeModal(newPostModal);
    })
    .catch(console.error)
    .finally(() => {
      btn.textContent = "Add Card";
      btn.disabled = false;
    });
});

// -------------------------
// Edit Avatar
avatarForm.addEventListener("submit", (evt) => {
  evt.preventDefault();

  const btn = avatarForm.querySelector(".modal__save-btn");
  btn.textContent = "Saving...";
  btn.disabled = true;

  api
    .updateAvatar(avatarInput.value)
    .then((data) => {
      profileAvatar.src = data.avatar;
      closeModal(editAvatarModal);
    })
    .catch(console.error)
    .finally(() => {
      btn.textContent = "Save";
      btn.disabled = false;
    });
});

// -------------------------
// Init App
api
  .getAppInfo()
  .then(([userData, cards]) => {
    setUserInfo(userData);
    cards.forEach((card) => {
      cardsList.prepend(createCard(card));
    });
  })
  .catch(console.error);

// -------------------------
// Enable Validation
enableValidation();
