// -------------------------
// Validation settings
export const settings = {
  formSelector: ".modal__form",
  inputSelector: ".modal__input",
  submitButtonSelector: ".modal__save-btn",
  inactiveButtonClass: "modal__save-btn_disabled",
  inputErrorClass: "modal__input_type_error", // FIXED
  errorClass: "modal__error_visible",
};

// -------------------------
// Show input error
export const showInputError = (form, input, message, settings) => {
  const errorEl = form.querySelector(`#${input.id}-error`);
  if (!errorEl) return;

  errorEl.textContent = message;
  errorEl.classList.add(settings.errorClass);
  input.classList.add(settings.inputErrorClass);
};

// -------------------------
// Hide input error
export const hideInputError = (form, input, settings) => {
  const errorEl = form.querySelector(`#${input.id}-error`);
  if (!errorEl) return;

  errorEl.textContent = "";
  errorEl.classList.remove(settings.errorClass);
  input.classList.remove(settings.inputErrorClass);
};

// -------------------------
// Check validity
export const checkInputValidity = (form, input, settings) => {
  if (!input.validity.valid) {
    showInputError(form, input, input.validationMessage, settings);
  } else {
    hideInputError(form, input, settings);
  }
};

// -------------------------
// Button state
export const hasInvalidInput = (inputs) =>
  inputs.some((input) => !input.validity.valid);

export const disableButton = (button) => {
  button.classList.add(settings.inactiveButtonClass);
  button.disabled = true;
};

export const enableButton = (button) => {
  button.classList.remove(settings.inactiveButtonClass);
  button.disabled = false;
};

export const toggleButtonState = (inputs, button) => {
  if (!button) return;

  if (hasInvalidInput(inputs)) {
    disableButton(button);
  } else {
    enableButton(button);
  }
};

// -------------------------
// Form listeners
export const setFormEventListeners = (form) => {
  if (!form) return;

  const inputs = Array.from(form.querySelectorAll(settings.inputSelector));
  const button = form.querySelector(settings.submitButtonSelector);

  toggleButtonState(inputs, button);

  inputs.forEach((input) => {
    input.addEventListener("input", () => {
      checkInputValidity(form, input, settings);
      toggleButtonState(inputs, button);
    });
  });
};

// -------------------------
// Reset validation
export const resetValidation = (form) => {
  if (!form) return;

  const inputs = Array.from(form.querySelectorAll(settings.inputSelector));
  const button = form.querySelector(settings.submitButtonSelector);

  inputs.forEach((input) => {
    hideInputError(form, input, settings);
  });

  toggleButtonState(inputs, button);
};

// -------------------------
// Enable validation
export const enableValidation = () => {
  const forms = document.querySelectorAll(settings.formSelector);
  forms.forEach(setFormEventListeners);
};

// -------------------------
// Modal logic

function handleEscClose(evt) {
  if (evt.key === "Escape") {
    const openedModal = document.querySelector(".modal_is-opened");
    if (openedModal) closeModal(openedModal);
  }
}

export function openModal(modal) {
  modal.classList.add("modal_is-opened");
  document.addEventListener("keydown", handleEscClose);

  const form = modal.querySelector("form");
  if (form) resetValidation(form);
}

export function closeModal(modal) {
  modal.classList.remove("modal_is-opened");
  document.removeEventListener("keydown", handleEscClose);
}

// -------------------------
// Setup modal (MATCHES your index.js)

export function setupModal(modalSelector, openButtons, closeSelectors) {
  const modal = document.querySelector(modalSelector);
  if (!modal) return null;

  const closeButtons = modal.querySelectorAll(closeSelectors.join(","));

  // Open modal
  openButtons.forEach((btn) => {
    btn?.addEventListener("click", () => openModal(modal));
  });

  // Close buttons
  closeButtons.forEach((btn) => {
    btn.addEventListener("click", () => closeModal(modal));
  });

  // Overlay click
  modal.addEventListener("mousedown", (evt) => {
    if (evt.target === modal) {
      closeModal(modal);
    }
  });

  return modal;
}
